package org.joda.time.field;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.joda.time.field.steps"
)
public class CucumberTest {
}

package org.joda.time.field.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.joda.time.Partial;
import org.joda.time.DateTimeFieldType;

import static org.junit.Assert.*;

public class StepDefs {

    private DateTimeFieldType[] fieldTypes;
    private int[] values;
    private Exception exception;

    @Given("the field types are {string}")
    public void the_field_types_are(String typesString) {
        // Parse the string representation of field types
        String[] typeNames = typesString.replaceAll("[\\[\\]]", "").split(", ");

        fieldTypes = new DateTimeFieldType[typeNames.length];
        for (int i = 0; i < typeNames.length; i++) {
            String typeName = typeNames[i].trim();

            switch(typeName) {
                case "year":
                    fieldTypes[i] = DateTimeFieldType.year();
                    break;
                case "era":
                    fieldTypes[i] = DateTimeFieldType.era();
                    break;
                case "monthOfYear":
                    fieldTypes[i] = DateTimeFieldType.monthOfYear();
                    break;
                case "dayOfMonth":
                    fieldTypes[i] = DateTimeFieldType.dayOfMonth();
                    break;
                default:
                    // Handle other field types as needed
                    throw new RuntimeException("Unknown field type: " + typeName);
            }
        }
    }

    @Given("the values are {string}")
    public void the_values_are(String valuesString) {
        String[] valuesStr = valuesString.replaceAll("[\\[\\]]", "").split(", ");
        values = new int[valuesStr.length];
        for (int i = 0; i < valuesStr.length; i++) {
            values[i] = Integer.parseInt(valuesStr[i].trim());
        }
    }

    @When("I construct a Partial with these types and values")
    public void i_construct_a_partial_with_these_types_and_values() {
        exception = null;
        try {
            new Partial(fieldTypes, values);
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the construction should fail with an IllegalArgumentException")
    public void the_construction_should_fail_with_an_illegalArgumentException() {
        assertNotNull("Expected construction to fail with an exception", exception);
        assertTrue("Expected IllegalArgumentException but got " + exception.getClass().getSimpleName(),
                   exception instanceof IllegalArgumentException);
    }

    @Then("the exception message should indicate that the types must be in order largest-smallest")
    public void the_exception_message_should_indicate_that_the_types_must_be_in_order_largest_smallest() {
        assertNotNull("Expected an exception", exception);
        String message = exception.getMessage();
        assertTrue("Expected exception message to indicate types must be in order largest-smallest, but got: " + message,
                   message != null && (message.toLowerCase().contains("largest") || 
                                      message.toLowerCase().contains("smallest") ||
                                      message.toLowerCase().contains("order")));
    }
}

